    total_populasi = VALUES(total_populasi),
    jumlah_negara_co2 = VALUES(jumlah_negara_co2),
    total_emisi_co2 = VALUES(total_emisi_co2),
    co2_per_capita = VALUES(co2_per_capita);
END 
